const raw = $json.stdout || '';
const lines = raw.split(/\r?\n/).filter(Boolean);
const marker = lines.find((l) => l.startsWith('N8N_SUMMARY='));
if (!marker) {
  return [{
    json: {
      ok: false,
      status: 'PARSER_ERROR',
      message: 'N8N_SUMMARY marker not found in stdout',
      attempts: 0,
      exit_code: 98,
      run_id: '',
      generated_at: new Date().toISOString(),
      signal_count: 0,
      gate_t1: false,
      gate_swing: false
    }
  }];
}
try {
  const parsed = JSON.parse(marker.slice('N8N_SUMMARY='.length));
  return [{ json: parsed }];
} catch (e) {
  return [{
    json: {
      ok: false,
      status: 'PARSER_ERROR',
      message: `JSON parse failed: ${e.message}`,
      attempts: 0,
      exit_code: 97,
      run_id: '',
      generated_at: new Date().toISOString(),
      signal_count: 0,
      gate_t1: false,
      gate_swing: false
    }
  }];
}

